2	\N	lendable V1	ui	\N	draft	2026-04-08 17:19:17.430328+00	2026-04-09 10:03:21.268+00	{"summary": "This configuration implements a comprehensive forbearance framework for unsecured personal loans based on SOP-COL-007. It includes seven distinct treatments: statutory actions (Breathing Space), third-party plans (DMP), structured internal arrangements (Payment Plan, Payment Deferral, Interest Freeze), and short-term tactical options (Account Hold, Promise to Pay). Eligibility is driven by arrears status, customer engagement, and formal notifications, with safety blocks for active insolvency, litigation, and DCA placement.", "treatments": [{"name": "Breathing Space", "priority": 1, "blocked_if": [], "confidence": "high", "description": "Statutory moratorium under the Debt Respite Scheme. Applied following notification from an approved debt advice provider. Halts all collections activity and freezes interest and charges.", "source_fields": [{"field_name": "breathing_space_ref", "description": "The unique reference number for an active Breathing Space case.", "matched_existing_field": true}], "when_to_offer": [{"reason": "SOP 4.6: Triggered by formal notification from a debt advice provider.", "operator": "is_true", "field_name": "breathing_space_notification_received", "field_type": "business"}, {"reason": "SOP 4.6: A Breathing Space reference number must be provided.", "operator": "exists", "field_name": "breathing_space_ref", "field_type": "source"}], "derived_fields": [], "business_fields": [{"data_type": "string", "field_name": "breathing_space_notification_received", "description": "A flag indicating the firm has received a formal notification to apply Breathing Space.", "display_name": "", "default_value": "", "allowed_values": [], "creation_reason": "", "business_meaning": ""}], "blocked_if_logic": "ANY", "when_to_offer_logic": "ALL"}, {"name": "Debt Management Plan (DMP)", "priority": 2, "blocked_if": [], "confidence": "high", "description": "Third-party managed arrangement where a money adviser distributes the customer's affordable payment across creditors. Interest is typically frozen.", "source_fields": [], "when_to_offer": [{"reason": "SOP 4.7: Triggered by notification from an approved money advice organisation.", "operator": "is_true", "field_name": "dmp_notification_received", "field_type": "business"}], "derived_fields": [], "business_fields": [{"data_type": "string", "field_name": "dmp_notification_received", "description": "A flag indicating the firm has received a formal notification to place the customer on a DMP.", "display_name": "", "default_value": "", "allowed_values": [], "creation_reason": "", "business_meaning": ""}], "blocked_if_logic": "ANY", "when_to_offer_logic": "ALL"}, {"name": "Payment Plan", "priority": 3, "blocked_if": [{"value": "Yes", "reason": "SOP 4.1: The account has no active Breathing Space moratorium.", "operator": "equals", "field_name": "breathing_space_active", "field_type": "source"}, {"value": "Yes", "reason": "SOP 4.1: There is no active insolvency on the account.", "operator": "equals", "field_name": "active_insolvency", "field_type": "source"}, {"value": "Yes", "reason": "SOP 4.1: There is no active DCA third-party placement.", "operator": "equals", "field_name": "active_dca_placement", "field_type": "source"}, {"reason": "SOP 4.1: There is no active litigation.", "operator": "is_true", "field_name": "litigation_active", "field_type": "business"}], "confidence": "high", "description": "Structured arrangement to repay arrears via reduced monthly instalments, calculated from an I&E assessment.", "source_fields": [{"field_name": "arrears_balance_gbp", "description": "The total overdue amount on the loan account.", "matched_existing_field": true}, {"field_name": "ie_assessment_completed", "description": "A flag indicating whether a formal I&E assessment has been completed.", "matched_existing_field": true}, {"field_name": "breathing_space_active", "description": "Indicator showing w